#include<bits/stdc++.h>#include<ext/pb_ds/assoc_container.hpp>#include<ext/pb_ds/tree_policy.hpp>using namespace std;using namespace __gnu_pbds; #define nl "\n"#define vll vector<ll>#define pb push_back#define mp make_pair#define YES cout<<"YES\n"#define NO cout<<"NO\n"#define sz(a) (int)a.size()#define fl for(int i=0; i<n; i++)#define tfl for(int i=1; i<=t; i++)#define all(a) (a).begin(),(a).end()#define rall(x) (x).rbegin(), (x).rend()#define mem(a,b) memset(a,b,sizeof(a))#define FASTER ios_base::sync_with_stdio(0); cin.tie(0); cout.tie(0);template <typename T> using ordered_set = tree<T,null_type, less<T>, rb_tree_tag, tree_order_statistics_node_update>; using ll = long long;using lld = long double;using ull = unsigned long long; const ll N = 1e5+10;const ll mod = 1e9+7;const ll INF = LONG_LONG_MAX;const lld pi = 3.141592653589793238; void solve(){    ll n;    cin>>n;    vector<ll>ans;    ll l=1, r=3*n;    for(int i=0; i<n; i++){        ans.pb(l);        ans.pb(r-1);        ans.pb(r);        l++;        r -= 2;    }    for(int i=0; i<ans.size(); i++){        cout<<ans[i]<<" ";    }    cout<<nl;} int main(){    FASTER    ll t;    cin>>t;    while(t--){    	solve();    }}